// React: empty state with starter chips
const STARTER_CHIPS = [
  "What's the status of my latest order?",
  "How do I return an item?",
  "What are your shipping options?",
];

function ChatInput({ onSubmit }: { onSubmit: (text: string) => void }) {
  const [value, setValue] = React.useState("");

  return (
    <div className="chat-input-container">
      <textarea
        value={value}
        onChange={e => setValue(e.target.value)}
        placeholder="Ask me about your orders, returns, or account"
        rows={2}
      />
      <button onClick={() => { onSubmit(value); setValue(""); }}>
        Send
      </button>

      {/* Only show chips before first message */}
      {value === "" && (
        <div className="starter-chips">
          {STARTER_CHIPS.map(chip => (
            <button
              key={chip}
              className="chip"
              onClick={() => { setValue(chip); onSubmit(chip); }}
            >
              {chip}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// Capability badge in chat header
interface AICapabilities {
  hasAccountAccess: boolean;
  hasOrderHistory: boolean;
  knowledgeCutoff: string;
}

function ChatHeader({ capabilities }: { capabilities: AICapabilities }) {
  return (
    <header className="chat-header">
      <div className="ai-identity">
        <span className="ai-name">Aria</span>
        <span className="ai-label">AI Assistant</span>
      </div>
      <div className="capability-badges">
        {capabilities.hasAccountAccess && (
          <span className="badge badge-green">Has your account info</span>
        )}
        {capabilities.hasOrderHistory && (
          <span className="badge badge-blue">Sees your orders</span>
        )}
      </div>
    </header>
  );
}

// Inline confidence and scope indicators on AI messages
interface AIMessage {
  content: string;
  confidence: "high" | "medium" | "low";
  sources?: string[];
  outOfScope?: boolean;
}

function AIMessageBubble({ message }: { message: AIMessage }) {
  return (
    <div className="ai-message">
      <p>{message.content}</p>

      {message.confidence === "low" && (
        <p className="confidence-disclaimer text-sm text-amber-600">
          ⚠️ I'm not fully certain about this — please verify with official sources.
        </p>
      )}

      {message.outOfScope && (
        <div className="scope-note">
          <p>This is outside what I can help with directly.</p>
          <a href="/support">Contact human support →</a>
        </div>
      )}

      {message.sources && message.sources.length > 0 && (
        <details className="sources">
          <summary>Sources</summary>
          <ul>
            {message.sources.map(s => <li key={s}>{s}</li>)}
          </ul>
        </details>
      )}
    </div>
  );
}

// Action bar shown on each AI response
interface MessageActionsProps {
  onRegenerate: () => void;
  onCopy: () => void;
  onFeedback: (positive: boolean) => void;
  onRefine: (instruction: string) => void;
}

const QUICK_REFINES = ["Shorter", "More formal", "Add examples", "Simplify"];

function MessageActions({ onRegenerate, onCopy, onFeedback, onRefine }: MessageActionsProps) {
  return (
    <div className="message-actions" role="toolbar" aria-label="Response actions">
      <button onClick={onRegenerate} title="Try again">
        ↻ Regenerate
      </button>
      <button onClick={onCopy} title="Copy to clipboard">
        ⧉ Copy
      </button>
      <button onClick={() => onFeedback(true)} title="Good response">
        👍
      </button>
      <button onClick={() => onFeedback(false)} title="Bad response">
        👎
      </button>

      <div className="quick-refine">
        {QUICK_REFINES.map(r => (
          <button key={r} className="chip" onClick={() => onRefine(r)}>
            {r}
          </button>
        ))}
      </div>
    </div>
  );
}

// Streaming-aware message display
function StreamingMessage({ content, isStreaming }: { content: string; isStreaming: boolean }) {
  return (
    <div className="ai-message">
      {content === "" && isStreaming ? (
        // Nothing yet — show typing indicator
        <div className="typing-indicator" aria-label="AI is thinking">
          <span /><span /><span />  {/* animated dots via CSS */}
        </div>
      ) : (
        <>
          <p>{content}</p>
          {isStreaming && (
            // Content appearing — show cursor to signal more is coming
            <span className="streaming-cursor" aria-hidden>▌</span>
          )}
        </>
      )}
    </div>
  );
}

// With a cancel button during long generation:
function MessageWithCancel({
  content, isStreaming, onCancel
}: { content: string; isStreaming: boolean; onCancel: () => void }) {
  return (
    <div>
      <StreamingMessage content={content} isStreaming={isStreaming} />
      {isStreaming && (
        <button className="cancel-btn" onClick={onCancel}>Stop generating</button>
      )}
    </div>
  );
}
